// ✏️ CAMBIA ESTE ID cuando crees tu barbería real
const BARBERSHOP_ID = 'TU_BARBERSHOP_ID';
const BASE = 'https://eslygfjpxwrjnoimsrly.supabase.co';
const KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVzbHlnZmpweHdyam5vaW1zcmx5Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Nzg1ODE0MCwiZXhwIjoyMDkzNDM0MTQwfQ.zTMI8PjaF6L785B69zRUDeEqPcYz4LE1DrYo-7tpaP0';
const OPENAI = 'TU_OPENAI_API_KEY';
const TODAY = new Date().toISOString().split('T')[0];

return [{ json: {
  barbershop_id: BARBERSHOP_ID, today: TODAY, base: BASE, key: KEY, openai: OPENAI,
  appts_url: `${BASE}/rest/v1/appointments?barbershop_id=eq.${BARBERSHOP_ID}&appointment_date=eq.${TODAY}&status=in.(scheduled,confirmed,pending)&select=start_time,end_time&order=start_time.asc`,
  clients_url: `${BASE}/rest/v1/clients?barbershop_id=eq.${BARBERSHOP_ID}&phone=not.is.null&select=name,phone&order=created_at.desc&limit=20`
}}];

const cfg = $('📅 Configurar día de hoy').item.json;
const appts = Array.isArray($input.first().json) ? $input.first().json : [];

// Horario de trabajo: 09:00 - 20:00 (660 minutos)
const OPEN = 9 * 60;   // 09:00 en minutos
const CLOSE = 20 * 60; // 20:00 en minutos

const toMin = t => { const [h,m] = (t || '09:00').split(':').map(Number); return h*60+m; };
const toHHMM = m => `${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`;

// Bloques ocupados
const busy = appts.map(a => ({ s: toMin(a.start_time), e: toMin(a.end_time) })).sort((a,b) => a.s-b.s);

// Calcular huecos libres >= 30 minutos
const gaps = [];
let cursor = OPEN;
for (const b of busy) {
  if (b.s - cursor >= 30) gaps.push({ from: toHHMM(cursor), to: toHHMM(b.s), mins: b.s - cursor });
  cursor = Math.max(cursor, b.e);
}
if (CLOSE - cursor >= 30) gaps.push({ from: toHHMM(cursor), to: toHHMM(CLOSE), mins: CLOSE - cursor });

const totalFreeHours = Math.round(gaps.reduce((s,g) => s+g.mins, 0) / 60 * 10) / 10;
const gapsSummary = gaps.map(g => `${g.from}-${g.to} (${g.mins} min)`).join(', ') || 'Sin huecos';

return [{ json: {
  ...cfg,
  total_booked: appts.length,
  free_slots: gaps.length,
  free_hours: totalFreeHours,
  gaps_summary: gapsSummary,
  has_gaps: gaps.length > 0
}}];

const clients = Array.isArray($input.first().json) ? $input.first().json : [];
if (clients.length === 0) return [];

const gapsSummary = $('🔍 Calcular huecos libres').item.json.gaps_summary;
const today = $('📅 Configurar día de hoy').item.json.today;
const openai = $('📅 Configurar día de hoy').item.json.openai;
const barbershop_id = $('📅 Configurar día de hoy').item.json.barbershop_id;

// Limite a 10 clientes para no spamear
const targets = clients.slice(0, 10);

return targets.map(c => ({
  json: {
    phone: c.phone,
    name: c.name,
    openai_key: openai,
    barbershop_id,
    prompt: `Redacta un mensaje WhatsApp de máximo 2 líneas para ${c.name || 'cliente'} avisando que hoy hay huecos disponibles en los siguientes horarios: ${gapsSummary}. Incluye invitación a reservar. Amable, conciso, sin spam.`
  }
}));
